22	  password: string;
23	  passwordSource: "env" | "passwordFile" | "config" | "none";
24	  config: IrcAccountConfig;
25	};
26	
27	function parseTruthy(value?: string): boolean {
28	  if (!value) {
29	    return false;
30	  }
31	  return TRUTHY_ENV.has(value.trim().toLowerCase());
32	}
33	
34	function parseIntEnv(value?: string): number | undefined {
35	  if (!value?.trim()) {
36	    return undefined;
37	  }
38	  const parsed = Number.parseInt(value.trim(), 10);
39	  if (!Number.isFinite(parsed) || parsed <= 0 || parsed > 65535) {
40	    return undefined;
41	  }
42	  return parsed;
43	}
