173	    useAccessGroups,
174	    authorizers: [
175	      {
176	        configured: (message.isGroup ? effectiveGroupAllowFrom : effectiveAllowFrom).length > 0,
177	        allowed: senderAllowedForCommands,
178	      },
179	    ],
180	    allowTextCommands,
181	    hasControlCommand,
182	  });
183	  const commandAuthorized = commandGate.commandAuthorized;
184	
185	  if (message.isGroup) {
186	    const senderAllowed = resolveIrcGroupSenderAllowed({
187	      groupPolicy,
188	      message,
189	      outerAllowFrom: effectiveGroupAllowFrom,
190	      innerAllowFrom: groupAllowFrom,
191	      allowNameMatching,
192	    });
193	    if (!senderAllowed) {
194	      runtime.log?.(`irc: drop group sender ${senderDisplay} (policy=${groupPolicy})`);
195	      return;
196	    }
197	  } else {
