import type { PulseboardInboundMessage } from "./types.js";

const PULSEBOARD_TARGET_PATTERN = /^[^\s]+$/u;

/** Returns true if the target represents a PulseBoard board (group chat). */
export function isPulseboardBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

/**
 * Normalize a raw messaging target string to a canonical form.
 * - `board:general` or `#general` → `#general`
 * - `user:alice` or `alice` → `alice`
 * Returns undefined when the target is invalid.
 */
export function normalizePulseboardMessagingTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) {
    return undefined;
  }
  let target = trimmed;

  // Strip channel-level prefix (e.g. "pulseboard:board:general")
  if (target.toLowerCase().startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }

  // board:<name> → #<name>
  if (target.toLowerCase().startsWith("board:")) {
    target = target.slice("board:".length).trim();
    if (!target.startsWith("#")) {
      target = `#${target}`;
    }
  }

  // user:<id> → <id>
  if (target.toLowerCase().startsWith("user:")) {
    target = target.slice("user:".length).trim();
  }

  if (!target || !looksLikePulseboardTargetId(target)) {
    return undefined;
  }
  return target;
}

export function looksLikePulseboardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) {
    return false;
  }
  return PULSEBOARD_TARGET_PATTERN.test(trimmed);
}

/**
 * Normalize a single allowFrom entry to lowercase canonical form.
 * Strips protocol/user prefixes so entries can be compared uniformly.
 */
export function normalizePulseboardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) {
    return "";
  }
  if (value.startsWith("pulseboard:")) {
    value = value.slice("pulseboard:".length);
  }
  if (value.startsWith("user:")) {
    value = value.slice("user:".length);
  }
  return value.trim();
}

export function normalizePulseboardAllowlist(entries?: Array<string | number>): string[] {
  return (entries ?? [])
    .map((entry) => normalizePulseboardAllowEntry(String(entry)))
    .filter(Boolean);
}

/**
 * Build the set of candidate identifiers for an inbound message sender.
 * PulseBoard senders are identified by their user id; name matching is
 * opt-in via allowNameMatching.
 */
export function buildPulseboardAllowlistCandidates(
  message: PulseboardInboundMessage,
  params?: { allowNameMatching?: boolean },
): string[] {
  const candidates = new Set<string>();
  const id = message.senderId.trim().toLowerCase();
  if (id) {
    candidates.add(id);
  }
  if (params?.allowNameMatching) {
    const name = message.senderName.trim().toLowerCase();
    if (name) {
      candidates.add(name);
    }
  }
  return [...candidates];
}

export function resolvePulseboardAllowlistMatch(params: {
  allowFrom: string[];
  message: PulseboardInboundMessage;
  allowNameMatching?: boolean;
}): { allowed: boolean; source?: string } {
  const allowFrom = new Set(
    params.allowFrom.map((entry) => entry.trim().toLowerCase()).filter(Boolean),
  );
  if (allowFrom.has("*")) {
    return { allowed: true, source: "wildcard" };
  }
  const candidates = buildPulseboardAllowlistCandidates(params.message, {
    allowNameMatching: params.allowNameMatching,
  });
  for (const candidate of candidates) {
    if (allowFrom.has(candidate)) {
      return { allowed: true, source: candidate };
    }
  }
  return { allowed: false };
}

