import { describeAccountSnapshot } from "openclaw/plugin-sdk/account-helpers";
import { formatNormalizedAllowFromEntries } from "openclaw/plugin-sdk/allow-from";
import {
  adaptScopedAccountAccessor,
  createScopedChannelConfigAdapter,
  createScopedDmSecurityResolver,
} from "openclaw/plugin-sdk/channel-config-helpers";
import {
  composeAccountWarningCollectors,
  createAllowlistProviderOpenWarningCollector,
} from "openclaw/plugin-sdk/channel-policy";
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import {
  createChannelDirectoryAdapter,
  createResolvedDirectoryEntriesLister,
} from "openclaw/plugin-sdk/directory-runtime";
import { runStoppablePassiveMonitor } from "openclaw/plugin-sdk/extension-shared";
import {
  createComputedAccountStatusAdapter,
  createDefaultChannelRuntimeState,
} from "openclaw/plugin-sdk/status-helpers";
import {
  listPulseboardAccountIds,
  resolvePulseboardAccount,
  resolveDefaultPulseboardAccountId,
  type ResolvedPulseboardAccount,
} from "./accounts.js";
import { PulseboardChannelConfigSchema } from "./config-schema.js";
import { monitorPulseboardProvider, probePulseboard } from "./monitor.js";
import {
  isPulseboardBoardTarget,
  looksLikePulseboardTargetId,
  normalizePulseboardAllowEntry,
  normalizePulseboardAllowlist,
  normalizePulseboardMessagingTarget,
} from "./normalize.js";
import {
  resolvePulseboardGroupMatch,
  resolvePulseboardRequireMention,
} from "./policy.js";
import {
  buildBaseChannelStatusSummary,
  chunkTextForOutbound,
  createAccountStatusSink,
  DEFAULT_ACCOUNT_ID,
  getChatChannelMeta,
  PAIRING_APPROVED_MESSAGE,
  type ChannelPlugin,
} from "./runtime-api.js";
import { getPulseboardRuntime } from "./runtime.js";
import { sendMessagePulseboard } from "./send.js";
import { pulseboardSetupAdapter } from "./setup-core.js";
import { pulseboardSetupWizard } from "./setup-surface.js";
import type { CoreConfig, PulseboardProbe } from "./types.js";

const meta = getChatChannelMeta("pulseboard");

function normalizePairingTarget(raw: string): string {
  const normalized = normalizePulseboardAllowEntry(raw);
  return normalized.trim();
}

const listPulseboardDirectoryPeersFromConfig =
  createResolvedDirectoryEntriesLister<ResolvedPulseboardAccount>({
    kind: "user",
    resolveAccount: adaptScopedAccountAccessor(resolvePulseboardAccount),
    resolveSources: (account) => [
      account.config.allowFrom ?? [],
      account.config.groupAllowFrom ?? [],
      ...Object.values(account.config.groups ?? {}).map((group) => group.allowFrom ?? []),
    ],
    normalizeId: (entry) => normalizePairingTarget(entry) || null,
  });

const listPulseboardDirectoryBoardsFromConfig =
  createResolvedDirectoryEntriesLister<ResolvedPulseboardAccount>({
    kind: "group",
    resolveAccount: adaptScopedAccountAccessor(resolvePulseboardAccount),
    resolveSources: (account) => [
      account.config.boards ?? [],
      Object.keys(account.config.groups ?? {}),
    ],
    normalizeId: (entry) => {
      const normalized = normalizePulseboardMessagingTarget(entry);
      return normalized && isPulseboardBoardTarget(normalized) ? normalized : null;
    },
  });

const pulseboardConfigAdapter = createScopedChannelConfigAdapter<
  ResolvedPulseboardAccount,
  ResolvedPulseboardAccount,
  CoreConfig
>({
  sectionKey: "pulseboard",
  listAccountIds: listPulseboardAccountIds,
  resolveAccount: adaptScopedAccountAccessor(resolvePulseboardAccount),
  defaultAccountId: resolveDefaultPulseboardAccountId,
  clearBaseFields: ["name", "serverUrl", "apiKey", "apiKeyFile", "botUserId", "boards"],
  resolveAllowFrom: (account: ResolvedPulseboardAccount) => account.config.allowFrom,
  formatAllowFrom: (allowFrom) =>
    formatNormalizedAllowFromEntries({
      allowFrom,
      normalizeEntry: normalizePulseboardAllowEntry,
    }),
  resolveDefaultTo: (account: ResolvedPulseboardAccount) => account.config.defaultTo,
});

const resolvePulseboardDmPolicy = createScopedDmSecurityResolver<ResolvedPulseboardAccount>({
  channelKey: "pulseboard",
  resolvePolicy: (account) => account.config.dmPolicy,
  resolveAllowFrom: (account) => account.config.allowFrom,
  policyPathSuffix: "dmPolicy",
  normalizeEntry: (raw) => normalizePulseboardAllowEntry(raw),
});

const collectPulseboardGroupPolicyWarnings =
  createAllowlistProviderOpenWarningCollector<ResolvedPulseboardAccount>({
    providerConfigPresent: (cfg) => cfg.channels?.pulseboard !== undefined,
    resolveGroupPolicy: (account) => account.config.groupPolicy,
    buildOpenWarning: {
      surface: "PulseBoard boards",
      openBehavior: "allows all boards and senders (mention-gated)",
      remediation:
        'Prefer channels.pulseboard.groupPolicy="allowlist" with channels.pulseboard.groups',
    },
  });

const collectPulseboardSecurityWarnings = composeAccountWarningCollectors<
  ResolvedPulseboardAccount,
  { account: ResolvedPulseboardAccount; cfg: CoreConfig }
>(
  collectPulseboardGroupPolicyWarnings,
  (account) =>
    account.apiKeySource === "config" &&
    "- PulseBoard API key is stored in plain config (channels.pulseboard.apiKey); prefer apiKeyFile or the PULSEBOARD_API_KEY env var.",
);

export const pulseboardPlugin: ChannelPlugin<ResolvedPulseboardAccount, PulseboardProbe> =
  createChatChannelPlugin({
    base: {
      id: "pulseboard",
      meta: {
        ...meta,
        quickstartAllowFrom: true,
      },
      setup: pulseboardSetupAdapter,
      setupWizard: pulseboardSetupWizard,
      capabilities: {
        chatTypes: ["direct", "group"],
        media: false,
        blockStreaming: true,
      },
      reload: { configPrefixes: ["channels.pulseboard"] },
      configSchema: PulseboardChannelConfigSchema,
      config: {
        ...pulseboardConfigAdapter,
        isConfigured: (account) => account.configured,
        describeAccount: (account) =>
          describeAccountSnapshot({
            account,
            configured: account.configured,
            extra: {
              serverUrl: account.serverUrl,
              botUserId: account.botUserId,
              apiKeySource: account.apiKeySource,
            },
          }),
      },
      groups: {
        resolveRequireMention: ({ cfg, accountId, groupId }) => {
          const account = resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId });
          if (!groupId) {
            return true;
          }
          const match = resolvePulseboardGroupMatch({
            groups: account.config.groups,
            boardId: groupId,
          });
          return resolvePulseboardRequireMention({
            groupConfig: match.groupConfig,
            wildcardConfig: match.wildcardConfig,
          });
        },
        resolveToolPolicy: ({ cfg, accountId, groupId }) => {
          const account = resolvePulseboardAccount({ cfg: cfg as CoreConfig, accountId });
          if (!groupId) {
            return undefined;
          }
          const match = resolvePulseboardGroupMatch({
            groups: account.config.groups,
            boardId: groupId,
          });
          return match.groupConfig?.tools ?? match.wildcardConfig?.tools;
        },
      },
      messaging: {
        normalizeTarget: normalizePulseboardMessagingTarget,
        targetResolver: {
          looksLikeId: looksLikePulseboardTargetId,
          hint: "<#board|userId>",
        },
      },
      resolver: {
        resolveTargets: async ({ inputs, kind }) => {
          return inputs.map((input) => {
            const normalized = normalizePulseboardMessagingTarget(input);
            if (!normalized) {
              return {
                input,
                resolved: false,
                note: "invalid PulseBoard target",
              };
            }
            if (kind === "group") {
              const boardId = isPulseboardBoardTarget(normalized)
                ? normalized
                : `#${normalized}`;
              return { input, resolved: true, id: boardId, name: boardId };
            }
            if (isPulseboardBoardTarget(normalized)) {
              return { input, resolved: false, note: "expected user target" };
            }
            return { input, resolved: true, id: normalized, name: normalized };
          });
        },
      },
      directory: createChannelDirectoryAdapter({
        listPeers: async (params) => listPulseboardDirectoryPeersFromConfig(params),
        listGroups: async (params) => {
          const entries = await listPulseboardDirectoryBoardsFromConfig(params);
          return entries.map((entry) => ({ ...entry, name: entry.id }));
        },
      }),
      status: createComputedAccountStatusAdapter<ResolvedPulseboardAccount, PulseboardProbe>({
        defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
        buildChannelSummary: ({ account, snapshot }) => ({
          ...buildBaseChannelStatusSummary(snapshot),
          serverUrl: account.serverUrl,
          botUserId: account.botUserId,
          probe: snapshot.probe,
          lastProbeAt: snapshot.lastProbeAt ?? null,
        }),
        probeAccount: async ({ cfg, account, timeoutMs }) =>
          probePulseboard(cfg as CoreConfig, { accountId: account.accountId, timeoutMs }),
        resolveAccountSnapshot: ({ account }) => ({
          accountId: account.accountId,
          name: account.name,
          enabled: account.enabled,
          configured: account.configured,
          extra: {
            serverUrl: account.serverUrl,
            botUserId: account.botUserId,
            apiKeySource: account.apiKeySource,
          },
        }),
      }),
      gateway: {
        startAccount: async (ctx) => {
          const account = ctx.account;
          const statusSink = createAccountStatusSink({
            accountId: ctx.accountId,
            setStatus: ctx.setStatus,
          });
          if (!account.configured) {
            throw new Error(
              `PulseBoard is not configured for account "${account.accountId}" (need serverUrl, apiKey, and botUserId in channels.pulseboard).`,
            );
          }
          ctx.log?.info(
            `[${account.accountId}] starting PulseBoard provider (${account.serverUrl})`,
          );
          await runStoppablePassiveMonitor({
            abortSignal: ctx.abortSignal,
            start: async () =>
              await monitorPulseboardProvider({
                accountId: account.accountId,
                config: ctx.cfg as CoreConfig,
                runtime: ctx.runtime,
                abortSignal: ctx.abortSignal,
                statusSink,
              }),
          });
        },
      },
    },
    pairing: {
      text: {
        idLabel: "pulseboardUser",
        message: PAIRING_APPROVED_MESSAGE,
        normalizeAllowEntry: (entry) => normalizePulseboardAllowEntry(entry),
        notify: async ({ id, message }) => {
          const target = normalizePairingTarget(id);
          if (!target) {
            throw new Error(`invalid PulseBoard pairing id: ${id}`);
          }
          await sendMessagePulseboard(target, message);
        },
      },
    },
    security: {
      resolveDmPolicy: resolvePulseboardDmPolicy,
      collectWarnings: collectPulseboardSecurityWarnings,
    },
    outbound: {
      base: {
        deliveryMode: "direct",
        chunker: chunkTextForOutbound,
        chunkerMode: "markdown",
        // PulseBoard supports up to 4000 characters per message.
        textChunkLimit: 4000,
      },
      attachedResults: {
        channel: "pulseboard",
        sendText: async ({ cfg, to, text, accountId, replyToId }) =>
          await sendMessagePulseboard(to, text, {
            cfg: cfg as CoreConfig,
            accountId: accountId ?? undefined,
            replyToId: replyToId ?? undefined,
          }),
        sendMedia: async ({ cfg, to, text, mediaUrl, accountId, replyToId }) =>
          await sendMessagePulseboard(
            to,
            mediaUrl ? `${text}\n\nAttachment: ${mediaUrl}` : text,
            {
              cfg: cfg as CoreConfig,
              accountId: accountId ?? undefined,
              replyToId: replyToId ?? undefined,
            },
          ),
      },
    },
  });

