import { resolveLoggerBackedRuntime } from "openclaw/plugin-sdk/extension-shared";
import { resolvePulseboardAccount } from "./accounts.js";
import { handlePulseboardInbound } from "./inbound.js";
import { isPulseboardBoardTarget } from "./normalize.js";
import type { RuntimeEnv } from "./runtime-api.js";
import { getPulseboardRuntime } from "./runtime.js";
import type { CoreConfig, PulseboardInboundMessage, PulseboardProbe } from "./types.js";

/** Shape of a single message object returned by the PulseBoard polling endpoint. */
type PulseboardApiMessage = {
  id: string;
  boardId?: string | null;
  senderId: string;
  senderName?: string;
  text: string;
  createdAt?: number | string;
};

export type PulseboardMonitorOptions = {
  accountId?: string;
  config?: CoreConfig;
  runtime?: RuntimeEnv;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
  /** Override message handler (for testing). */
  onMessage?: (message: PulseboardInboundMessage) => void | Promise<void>;
};

function parsePulseboardTimestamp(value?: number | string): number {
  if (typeof value === "number") {
    return value;
  }
  if (typeof value === "string") {
    const parsed = Date.parse(value);
    return Number.isFinite(parsed) ? parsed : Date.now();
  }
  return Date.now();
}

/**
 * Poll the PulseBoard server for new messages.
 * Returns the array of message objects from the response, or an empty array on
 * any non-fatal error.
 */
async function pollPulseboardMessages(params: {
  serverUrl: string;
  apiKey: string;
  botUserId: string;
  since: number;
  signal?: AbortSignal;
}): Promise<PulseboardApiMessage[]> {
  const url = `${params.serverUrl}/messages?since=${params.since}&botUserId=${encodeURIComponent(params.botUserId)}`;
  const response = await fetch(url, {
    headers: { Authorization: `Bearer ${params.apiKey}` },
    signal: params.signal,
  });
  if (!response.ok) {
    throw new Error(`PulseBoard poll failed (${response.status}): ${response.statusText}`);
  }
  const json = (await response.json()) as { messages?: PulseboardApiMessage[] };
  return Array.isArray(json.messages) ? json.messages : [];
}

/**
 * Run the long-lived polling loop for a PulseBoard account.
 * Resolves when the abortSignal fires or after a fatal error.
 */
export async function monitorPulseboardProvider(
  opts: PulseboardMonitorOptions,
): Promise<{ stop: () => void }> {
  const core = getPulseboardRuntime();
  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
  const account = resolvePulseboardAccount({ cfg, accountId: opts.accountId });
  const runtime: RuntimeEnv = resolveLoggerBackedRuntime(opts.runtime, core.logging.getChildLogger());

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need serverUrl, apiKey, and botUserId in channels.pulseboard).`,
    );
  }

  const logger = core.logging.getChildLogger({
    channel: "pulseboard",
    accountId: account.accountId,
  });

  const pollIntervalMs = account.config.pollIntervalMs ?? 2000;
  let since = Date.now();
  let stopped = false;
  let intervalId: ReturnType<typeof setInterval> | null = null;

  logger.info(
    `[${account.accountId}] polling PulseBoard at ${account.serverUrl} every ${pollIntervalMs}ms`,
  );

  const tick = async () => {
    if (stopped || opts.abortSignal?.aborted) {
      return;
    }
    let messages: PulseboardApiMessage[];
    try {
      messages = await pollPulseboardMessages({
        serverUrl: account.serverUrl,
        apiKey: account.apiKey,
        botUserId: account.botUserId,
        since,
        signal: opts.abortSignal,
      });
    } catch (err) {
      if (!stopped && !opts.abortSignal?.aborted) {
        runtime.error?.(
          `[${account.accountId}] PulseBoard poll error: ${err instanceof Error ? err.message : String(err)}`,
        );
      }
      return;
    }

    for (const raw of messages) {
      if (stopped || opts.abortSignal?.aborted) {
        break;
      }
      const ts = parsePulseboardTimestamp(raw.createdAt);
      if (ts > since) {
        since = ts;
      }

      const boardId =
        typeof raw.boardId === "string" && raw.boardId
          ? raw.boardId.startsWith("#")
            ? raw.boardId
            : `#${raw.boardId}`
          : null;
      const isGroup = boardId !== null && isPulseboardBoardTarget(boardId);
      const message: PulseboardInboundMessage = {
        messageId: raw.id,
        boardId,
        senderId: raw.senderId,
        senderName: raw.senderName ?? raw.senderId,
        text: raw.text,
        timestamp: ts,
        isGroup,
      };

      core.channel.activity.record({
        channel: "pulseboard",
        accountId: account.accountId,
        direction: "inbound",
        at: message.timestamp,
      });

      if (opts.onMessage) {
        await opts.onMessage(message);
        continue;
      }

      await handlePulseboardInbound({
        message,
        account,
        config: cfg,
        runtime,
        sendReply: async (target, text, replyToId) => {
          const { sendMessagePulseboard } = await import("./send.js");
          await sendMessagePulseboard(target, text, {
            accountId: account.accountId,
            replyToId,
          });
          opts.statusSink?.({ lastOutboundAt: Date.now() });
          core.channel.activity.record({
            channel: "pulseboard",
            accountId: account.accountId,
            direction: "outbound",
          });
        },
        statusSink: opts.statusSink,
      });
    }
  };

  intervalId = setInterval(() => {
    void tick();
  }, pollIntervalMs);

  // Run first tick immediately.
  void tick();

  opts.abortSignal?.addEventListener("abort", () => {
    stopped = true;
    if (intervalId !== null) {
      clearInterval(intervalId);
      intervalId = null;
    }
  });

  return {
    stop: () => {
      stopped = true;
      if (intervalId !== null) {
        clearInterval(intervalId);
        intervalId = null;
      }
    },
  };
}

/**
 * Probe the PulseBoard server by hitting the health endpoint.
 * Returns a PulseboardProbe with ok=true and latency on success.
 */
export async function probePulseboard(
  cfg: CoreConfig,
  opts?: { accountId?: string; timeoutMs?: number },
): Promise<PulseboardProbe> {
  const account = resolvePulseboardAccount({ cfg, accountId: opts?.accountId });
  const base: PulseboardProbe = {
    ok: false,
    serverUrl: account.serverUrl,
    botUserId: account.botUserId,
  };

  if (!account.configured) {
    return { ...base, error: "missing serverUrl, apiKey, or botUserId" };
  }

  const timeoutMs = opts?.timeoutMs ?? 8000;
  const controller = new AbortController();
  const timerId = setTimeout(() => controller.abort(), timeoutMs);
  const started = Date.now();

  try {
    const response = await fetch(`${account.serverUrl}/health`, {
      headers: { Authorization: `Bearer ${account.apiKey}` },
      signal: controller.signal,
    });
    const elapsed = Date.now() - started;
    if (!response.ok) {
      return {
        ...base,
        error: `health check returned ${response.status} ${response.statusText}`,
      };
    }
    return { ...base, ok: true, latencyMs: elapsed };
  } catch (err) {
    return {
      ...base,
      error: err instanceof Error ? err.message : String(err),
    };
  } finally {
    clearTimeout(timerId);
  }
}

