import { describe, expect, it } from "vitest";
import {
  listPulseboardAccountIds,
  resolvePulseboardAccount,
  resolveDefaultPulseboardAccountId,
} from "./accounts.js";
import type { CoreConfig } from "./types.js";

function asConfig(value: unknown): CoreConfig {
  return value as CoreConfig;
}

describe("listPulseboardAccountIds", () => {
  it("returns default when no accounts are configured", () => {
    expect(listPulseboardAccountIds(asConfig({}))).toEqual(["default"]);
  });

  it("normalizes, deduplicates, and sorts configured account ids", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          accounts: {
            "Ops Team": {},
            "ops-team": {},
            Work: {},
          },
        },
      },
    });

    expect(listPulseboardAccountIds(cfg)).toEqual(["ops-team", "work"]);
  });
});

describe("resolveDefaultPulseboardAccountId", () => {
  it("prefers configured defaultAccount when it matches", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          defaultAccount: "Ops Team",
          accounts: {
            default: {},
            "ops-team": {},
          },
        },
      },
    });

    expect(resolveDefaultPulseboardAccountId(cfg)).toBe("ops-team");
  });

  it("falls back to default when configured defaultAccount is missing", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          defaultAccount: "missing",
          accounts: {
            default: {},
            work: {},
          },
        },
      },
    });

    expect(resolveDefaultPulseboardAccountId(cfg)).toBe("default");
  });

  it("falls back to first sorted account when default is absent", () => {
    const cfg = asConfig({
      channels: {
        pulseboard: {
          accounts: {
            zzz: {},
            aaa: {},
          },
        },
      },
    });

    expect(resolveDefaultPulseboardAccountId(cfg)).toBe("aaa");
  });
});

describe("resolvePulseboardAccount", () => {
  it("matches normalized configured account ids", () => {
    const account = resolvePulseboardAccount({
      cfg: asConfig({
        channels: {
          pulseboard: {
            accounts: {
              "Ops Team": {
                serverUrl: "https://pb.example.com",
                apiKey: "key-abc",
                botUserId: "bot-1",
              },
            },
          },
        },
      }),
      accountId: "ops-team",
    });

    expect(account.accountId).toBe("ops-team");
    expect(account.serverUrl).toBe("https://pb.example.com");
    expect(account.botUserId).toBe("bot-1");
    expect(account.configured).toBe(true);
  });

  it("reports not configured when serverUrl is missing", () => {
    const account = resolvePulseboardAccount({
      cfg: asConfig({
        channels: {
          pulseboard: {
            apiKey: "key-abc",
            botUserId: "bot-1",
          },
        },
      }),
    });

    expect(account.configured).toBe(false);
  });

  it("reports not configured when apiKey is missing", () => {
    const account = resolvePulseboardAccount({
      cfg: asConfig({
        channels: {
          pulseboard: {
            serverUrl: "https://pb.example.com",
            botUserId: "bot-1",
          },
        },
      }),
    });

    expect(account.configured).toBe(false);
    expect(account.apiKeySource).toBe("none");
  });

  it("resolves api key from config", () => {
    const account = resolvePulseboardAccount({
      cfg: asConfig({
        channels: {
          pulseboard: {
            serverUrl: "https://pb.example.com",
            apiKey: "my-secret-key",
            botUserId: "bot-99",
          },
        },
      }),
    });

