  normalizePulseboardMessagingTarget,
  resolvePulseboardAllowlistMatch,
} from "./normalize.js";
import type { PulseboardInboundMessage } from "./types.js";

function makeMessage(overrides?: Partial<PulseboardInboundMessage>): PulseboardInboundMessage {
  return {
    messageId: "msg-1",
    boardId: "#general",
    senderId: "alice",
    senderName: "Alice",
    text: "hello",
    timestamp: Date.now(),
    isGroup: true,
    ...overrides,
  };
}

describe("isPulseboardBoardTarget", () => {
  it("returns true for # prefixed targets", () => {
    expect(isPulseboardBoardTarget("#general")).toBe(true);
    expect(isPulseboardBoardTarget("#ops")).toBe(true);
  });

  it("returns false for non-board targets", () => {
    expect(isPulseboardBoardTarget("alice")).toBe(false);
    expect(isPulseboardBoardTarget("user-42")).toBe(false);
  });
});

describe("normalizePulseboardMessagingTarget", () => {
  it("normalizes board: prefix to # prefix", () => {
    expect(normalizePulseboardMessagingTarget("board:general")).toBe("#general");
    expect(normalizePulseboardMessagingTarget("board:#general")).toBe("#general");
  });

  it("passes through # prefixed board names unchanged", () => {
    expect(normalizePulseboardMessagingTarget("#general")).toBe("#general");
  });

  it("normalizes user: prefix", () => {
    expect(normalizePulseboardMessagingTarget("user:alice")).toBe("alice");
  });

  it("strips pulseboard: channel prefix", () => {
    expect(normalizePulseboardMessagingTarget("pulseboard:board:ops")).toBe("#ops");
    expect(normalizePulseboardMessagingTarget("pulseboard:alice")).toBe("alice");
  });

  it("returns undefined for empty or whitespace-only input", () => {
    expect(normalizePulseboardMessagingTarget("")).toBeUndefined();
    expect(normalizePulseboardMessagingTarget("   ")).toBeUndefined();
  });

  it("returns undefined for targets containing spaces", () => {
    expect(normalizePulseboardMessagingTarget("two words")).toBeUndefined();
  });
});

describe("looksLikePulseboardTargetId", () => {
  it("accepts single-word ids", () => {
    expect(looksLikePulseboardTargetId("alice")).toBe(true);
    expect(looksLikePulseboardTargetId("#general")).toBe(true);
  });

  it("rejects strings with whitespace", () => {
    expect(looksLikePulseboardTargetId("two words")).toBe(false);
    expect(looksLikePulseboardTargetId(" leading")).toBe(false);
  });

  it("rejects empty string", () => {
    expect(looksLikePulseboardTargetId("")).toBe(false);
  });
});

