    const message = makeMessage({ senderId: "unknown" });
    expect(
      resolvePulseboardAllowlistMatch({ allowFrom: ["*"], message }).allowed,
    ).toBe(true);
  });

  it("matches by sender id", () => {
    const message = makeMessage({ senderId: "alice" });
    expect(
      resolvePulseboardAllowlistMatch({ allowFrom: ["alice"], message }).allowed,
    ).toBe(true);
    expect(
      resolvePulseboardAllowlistMatch({ allowFrom: ["bob"], message }).allowed,
    ).toBe(false);
  });

  it("matches by sender name only when allowNameMatching=true", () => {
    const message = makeMessage({ senderId: "user-42", senderName: "Alice" });
    expect(
      resolvePulseboardAllowlistMatch({ allowFrom: ["alice"], message }).allowed,
    ).toBe(false);
    expect(
      resolvePulseboardAllowlistMatch({
        allowFrom: ["alice"],
        message,
        allowNameMatching: true,
      }).allowed,
    ).toBe(true);
  });
});

