import { describe, expect, it } from "vitest";
import {
  resolvePulseboardGroupAccessGate,
  resolvePulseboardGroupMatch,
  resolvePulseboardGroupSenderAllowed,
  resolvePulseboardMentionGate,
  resolvePulseboardRequireMention,
} from "./policy.js";
import type { PulseboardInboundMessage } from "./types.js";

function makeMessage(overrides?: Partial<PulseboardInboundMessage>): PulseboardInboundMessage {
  return {
    messageId: "m1",
    boardId: "#ops",
    senderId: "alice",
    senderName: "Alice",
    text: "hi",
    timestamp: Date.now(),
    isGroup: true,
    ...overrides,
  };
}

describe("resolvePulseboardGroupMatch", () => {
  it("matches direct board entry", () => {
    const match = resolvePulseboardGroupMatch({
      groups: { "#ops": { requireMention: false } },
      boardId: "#ops",
    });
    expect(match.allowed).toBe(true);
    expect(resolvePulseboardRequireMention({ groupConfig: match.groupConfig })).toBe(false);
  });

  it("matches case-insensitively", () => {
    const match = resolvePulseboardGroupMatch({
      groups: { "#Ops": { requireMention: false } },
      boardId: "#ops",
    });
    expect(match.allowed).toBe(true);
  });

  it("matches wildcard entry when no direct match", () => {
    const match = resolvePulseboardGroupMatch({
      groups: { "*": { requireMention: true } },
      boardId: "#random",
    });
    expect(match.allowed).toBe(true);
    expect(resolvePulseboardRequireMention({ wildcardConfig: match.wildcardConfig })).toBe(true);
  });

  it("returns not allowed when no match and no wildcard", () => {
    const match = resolvePulseboardGroupMatch({
      groups: { "#ops": {} },
      boardId: "#other",
    });
    expect(match.allowed).toBe(false);
  });
});

describe("resolvePulseboardGroupAccessGate", () => {
  it("blocks when groupPolicy=disabled", () => {
    const gate = resolvePulseboardGroupAccessGate({
      groupPolicy: "disabled",
      groupMatch: { allowed: true, hasConfiguredGroups: true },
    });
    expect(gate.allowed).toBe(false);
    expect(gate.reason).toBe("groupPolicy=disabled");
  });

  it("blocks when allowlist has no groups", () => {
    const gate = resolvePulseboardGroupAccessGate({
      groupPolicy: "allowlist",
      groupMatch: { allowed: false, hasConfiguredGroups: false },
    });
    expect(gate.allowed).toBe(false);
  });

  it('allows unconfigured boards when groupPolicy is "open"', () => {
    const gate = resolvePulseboardGroupAccessGate({
      groupPolicy: "open",
      groupMatch: { allowed: false, hasConfiguredGroups: false },
    });
    expect(gate.allowed).toBe(true);
    expect(gate.reason).toBe("open");
  });

  it("honors explicit board disable even in open mode", () => {
    const gate = resolvePulseboardGroupAccessGate({
      groupPolicy: "open",
      groupMatch: {
        allowed: true,
        groupConfig: { enabled: false },
        hasConfiguredGroups: true,
      },
    });
    expect(gate.allowed).toBe(false);
    expect(gate.reason).toBe("disabled");
  });
});

describe("resolvePulseboardMentionGate", () => {
  it("skips when mention required and not mentioned", () => {
    const gate = resolvePulseboardMentionGate({
      isGroup: true,
      requireMention: true,
      wasMentioned: false,
      hasControlCommand: false,
      allowTextCommands: false,
      commandAuthorized: false,
    });
    expect(gate.shouldSkip).toBe(true);
    expect(gate.reason).toBe("missing-mention");
  });

  it("does not skip when mention required and was mentioned", () => {
    const gate = resolvePulseboardMentionGate({
      isGroup: true,
      requireMention: true,
      wasMentioned: true,
      hasControlCommand: false,
      allowTextCommands: false,
      commandAuthorized: false,
    });
    expect(gate.shouldSkip).toBe(false);
  });

  it("allows authorized control commands without mention", () => {
    const gate = resolvePulseboardMentionGate({
      isGroup: true,
      requireMention: true,
      wasMentioned: false,
      hasControlCommand: true,
      allowTextCommands: true,
      commandAuthorized: true,
    });
    expect(gate.shouldSkip).toBe(false);
    expect(gate.reason).toBe("authorized-command");
  });

  it("does not skip for direct messages", () => {
    const gate = resolvePulseboardMentionGate({
      isGroup: false,
      requireMention: true,
      wasMentioned: false,
      hasControlCommand: false,
      allowTextCommands: false,
      commandAuthorized: false,
    });
    expect(gate.shouldSkip).toBe(false);
    expect(gate.reason).toBe("direct");
  });
});

describe("resolvePulseboardGroupSenderAllowed", () => {
  it("blocks when allowlist mode and no allowFrom entries", () => {
    expect(
      resolvePulseboardGroupSenderAllowed({
        groupPolicy: "allowlist",
        message: makeMessage(),
        outerAllowFrom: [],
        innerAllowFrom: [],
      }),
    ).toBe(false);
  });

  it("allows matching sender id in outerAllowFrom", () => {
    expect(
      resolvePulseboardGroupSenderAllowed({
        groupPolicy: "allowlist",
        message: makeMessage({ senderId: "alice" }),
        outerAllowFrom: ["alice"],
        innerAllowFrom: [],
      }),
    ).toBe(true);
  });

  it("innerAllowFrom takes priority over outerAllowFrom", () => {
    expect(
      resolvePulseboardGroupSenderAllowed({
        groupPolicy: "allowlist",
        message: makeMessage({ senderId: "alice" }),
        outerAllowFrom: ["alice"],
        innerAllowFrom: ["bob"],
      }),
    ).toBe(false);
  });

  it("allows all senders when policy is open and no allowFrom", () => {
    expect(
      resolvePulseboardGroupSenderAllowed({
        groupPolicy: "open",
        message: makeMessage({ senderId: "anyone" }),
        outerAllowFrom: [],
        innerAllowFrom: [],
      }),
    ).toBe(true);
  });
});

